 require.config({
   paths: {
 		'create-work-package-utils': new XWiki.Document(new XWiki.Model.resolve('Main.WebHome', XWiki.EntityType.DOCUMENT)).getURL
 		('jsx', 'resource=js/openproject/create-work-packages-utils.js&minify=false')
   }
 });

require(["jquery", "create-work-package-utils"], function ($, createWpUtils) {

  $(document).ready(function () {
    const baseUrl = `${XWiki.contextPath}/rest/wikis/${XWiki.currentWiki}/openproject/instance/`;
    let selectedText = "";
    let rowsData = [];
    let mapping = {};

    function resetCreateSingleWorkPackageForm() {
      $('#connection-select-single-work-package').val("");
      $("#project-select-single-work-package").val("").empty();
      $("#project-select-single-work-package-container").addClass("hidden");
      $("#project-select-single-work-package").prop("disabled", false);
      $("#single-dynamic-fields-container").empty().addClass("hidden");
      $("#incorrect-token-single-work-package").addClass("hidden");
    }

    function resetCreateMultipleWorkPackagesForm() {
      $("#work-packages-container").empty();
      $("#multiple-work-packages-container").addClass("hidden");
      $("#select-all-work-packages").prop("checked", true);
      $('#connection-select-multiple-work-packages').val("");
      $("#project-select-multiple-work-packages").val("").empty();
      $("#project-select-multiple-work-packages").prop("disabled", false);
      $("#mappings-container").empty();
      $("#work-packages-table-mapping-container").addClass("hidden");
      $("#project-select-multiple-work-packages-container").addClass("hidden");
      $("#incorrect-token-multiple-work-packages").addClass("hidden");
    }

    function generateCards(projectApiResponse, elements) {
      const template = $("#work-package-card-template");
      let container = $("#work-packages-container");
      let multipleWorkPackagesContainer = $("#multiple-work-packages-container");
      multipleWorkPackagesContainer.addClass("hidden");
	    container.empty()
      elements.forEach((element, index) => {
        let card = generateCard(template, projectApiResponse, element, index)
        container.append(card);
      });
      multipleWorkPackagesContainer.removeClass("hidden");
      $("#select-all-work-packages").prop("checked", true);
    }

    function generateCard(template, projectApiResponse, element, index) {
      const clone = template[0].content.cloneNode(true);
      const card = $(clone).find(".work-package-card");
      const collapseId = "advanced-options_" + index;

      const collapseOptions = card.find(".advanced-options");
      const toggle = card.find("[data-toggle='collapse']");
      const title = card.find(".wp-subject-title");

      title.attr("id", `wp-subject-title-${index}`);

      collapseOptions.attr("id", collapseId);
      toggle.attr("data-target", "#" + collapseId);

      const checkBoxInput = card.find("#wp-selected");
      checkBoxInput.attr("id", `wp-selected-${index}`);
      checkBoxInput.attr("name", `wp-selected-${index}`);
      const checkBoxLabel = card.find("label[for='wp-selected']");
      checkBoxLabel.attr("for", `wp-selected-${index}`);

      Object.entries(projectApiResponse).forEach(([key, value]) => {
        const id = `wp-${key}-${index}`;
		const inputClass = `wp-${key}`;
        const input = createWpUtils.createInput(id, key, inputClass, value);
        collapseOptions.append(input);
      });

      const subjectInput = card.find(".wp-subject");
      const defaultText = "Work package " + (index + 1);
      const valueToSet = element && element.trim() !== "" ? element : defaultText;

      subjectInput.val(valueToSet);
      title.text(valueToSet);

      return card;
    }

    function initializeMapping(response) {
      const container = $("#work-packages-table-mapping-container");
      container.removeClass("hidden");
      $('#mappings-container').empty();
      $("#add-mapping").off("click").on("click", function() {
        addMappingRow(rowsData, response);
      });
    }

    function addMappingRow(tableKeys, openProjectResponse) {
      const template = document.querySelector("#mapping-row-template");
      const clone = template.content.cloneNode(true);
      const row = $(clone).find(".mapping-row");

      const tableSelect = row.find(".table-key");
      const opSelect = row.find(".op-key");

      tableKeys = Object.keys(tableKeys[0] || {});

      tableKeys.forEach(key => {
        tableSelect.append(`<option value="${key}">${key}</option>`);
      });

      Object.entries(openProjectResponse).forEach(([key, value]) => {
        opSelect.append(
          `<option value="${key}">${value.label}</option>`
        );
      });

      tableSelect.add(opSelect).on("change", updateMapping);

      row.find(".delete-mapping").on("click", function() {
        const opKey = row.find(".op-key").val();
        row.remove();
        clearMappedField(opKey)
        updateMapping();
      });

      $("#mappings-container").append(row);
    }

    function updateMapping() {
      mapping = {};
      $(".mapping-row").each(function() {
        const tableKey = $(this).find(".table-key").val();
        const opKey = $(this).find(".op-key").val();
        if (tableKey && opKey) {
          mapping[tableKey] = opKey;
        }
      });

      applyMappingToCards();
    }

    function clearMappedField(opKey) {
      $(".work-package-card").each(function(index) {
        const inputId = `#wp-${opKey}-${index}`;
        const input = $(inputId);

        if (!input.length) {
          return;
        }

        if (input.is("select")) {
          input.prop("selectedIndex", 0).trigger("change");
        } else {
          if (input.hasClass("wp-subject")) {
            const defaultText = "Work package " + (index + 1);
            input.val(defaultText).trigger("change");
          } else {
            input.val("").trigger("change");
          }
        }
      });
    }

    function applyMappingToCards() {
      $(".work-package-card").each(function(index) {
        const rowData = rowsData[index];

        if (!rowData) {
          return;
        }

        Object.entries(mapping).forEach(([tableKey, opKey]) => {
          const value = rowData[tableKey];

          if (value === undefined || value === null) {
            return;
          }

          const inputId = `#wp-${opKey}-${index}`;
          const input = $(inputId);

          if (!input.length) {
            return;
          }

          if (input.is("select")) {
            const normalizedValue = String(value).trim().toLowerCase();

            const matchingOption = input.find("option").filter(function() {
            return $(this).text().trim().toLowerCase() === normalizedValue;
            });

            if (matchingOption.length) {
              input.val(matchingOption.val()).trigger("change");
            }
          } else {
            input.val(value).trigger("change");
          }
        });
      });
    }

    function findAndOpenFirstInvalid($container) {
      let firstInvalid = null;
      $container
        .find('input[required], select[required], textarea[required]')
        .each(function () {
          const $field = $(this);

          if ($field.hasClass('wp-selected')) {
            return;
          }

          const $checkbox = $field.closest('.work-package-card').find('.wp-selected');

          if ($checkbox.length && !$checkbox.is(':checked')) {
            return;
          }

          const value = $field.val();

          if (value === null || String(value).trim() === '') {
            firstInvalid = $field;
            return false;
          }
        });

      if (!firstInvalid) {
        return null;
      }

      const $collapse = firstInvalid.closest('.collapse');

      if ($collapse.length) {
        $collapse.one('shown.bs.collapse', function () {
          firstInvalid.trigger('focus');
        });

        $collapse.collapse('show');
      } else {
        firstInvalid.trigger('focus');
      }

      return firstInvalid;
    }

    function renderSingleMode() {
      resetCreateSingleWorkPackageForm();
      $("#wp-create-modal-title").text("Create Single Work Package");
      $("#create-multiple-work-packages-form").addClass("hidden");
      $("#create-single-work-package-form").removeClass("hidden");
    }

    function renderMultipleMode() {
      resetCreateMultipleWorkPackagesForm();
      $("#wp-create-modal-title").text("Create Multiple Work Packages");
      $("#create-multiple-work-packages-form").removeClass("hidden");
      $("#create-single-work-package-form").addClass("hidden");
    }

    function getConnection(isSingleWorkPackage) {
      if (isSingleWorkPackage) {
        return $("#connection-select-single-work-package").val();
      }

      return $("#connection-select-multiple-work-packages").val();
    }

    $('#create-wp').on('click', function(e) {
      e.preventDefault();
      const selection = window.getSelection();
      selectedText = selection.toString().trim();

      $('#selection-menu').hide();
      window.getSelection().removeAllRanges();

      renderSingleMode();
      $("#create-work-packages-modal").modal("show");

      const $connectionSelect = $("#connection-select-single-work-package");

      if ($connectionSelect.find("option").length === 1) {
        $connectionSelect.prop("selectedIndex", 0);
        $connectionSelect.prop("disabled", true);
        $connectionSelect.trigger("change");
      }
    });

    $('#create-wp-from-table').on('click', (e) => {
      e.preventDefault();

      const selection = window.getSelection();
      if (!selection.rangeCount) return;

      const range = selection.getRangeAt(0);
      const startNode = range.startContainer;

      const table = $(startNode).closest("table");
      if (!table.length) return;

      rowsData = [];

      const rows = table.find("tr");
      const headers = [];
      const hasHeader = rows.first().find("th").length > 0;

      if (hasHeader) {
        rows.first().find("th, td").each((_, el) => {
          headers.push($(el).text().trim());
        });
      } else {
        const colCount = rows.first().find("td").length;
        for (let i = 0; i < colCount; i++) {
          headers.push(`Col${i + 1}`);
        }
      }

      rows.each((rowIndex, rowEl) => {
        if (hasHeader && rowIndex === 0) {
            return;
          }

          const rowObject = {};
          const cells = $(rowEl).find("td");

          cells.each((cellIndex, cellEl) => {
            const key = headers[cellIndex];
            rowObject[key] = $(cellEl).text().trim();
          });

          if (Object.keys(rowObject).length > 0) {
            rowsData.push(rowObject);
          }
      });

      $('#selection-menu').hide();
      window.getSelection().removeAllRanges();

      renderMultipleMode();
      $("#create-work-packages-modal").modal("show");

      const $connectionSelect = $("#connection-select-multiple-work-packages");
      if ($connectionSelect.find("option").length === 1) {
        $connectionSelect.prop("selectedIndex", 0);
        $connectionSelect.prop("disabled", true);
        $connectionSelect.trigger("change");
      }
    });

    $("#work-packages-container").on('input change', '.wp-subject', function() {
      const input = $(this);
      const inputId = input.attr('id');
      const index = inputId.split('-').pop();
      const titleId = `#wp-subject-title-${index}`;
      $(titleId).text(input.val());
    });

    $("#connection-select-multiple-work-packages").on("change", function () {
      createWpUtils.loadProjects(
        "#connection-select-multiple-work-packages",
        "#project-select-multiple-work-packages",
        "#project-select-multiple-work-packages-container",
        "#incorrect-token-multiple-work-packages"
      );
      $("#mappings-container").empty();
			$("#work-packages-table-mapping-container").addClass("hidden");
			$("#multiple-work-packages-container").addClass("hidden");
    });

    $("#connection-select-single-work-package").on("change", function () {
      $("#single-dynamic-fields-container").empty().addClass("hidden");
      createWpUtils.loadProjects(
        "#connection-select-single-work-package",
        "#project-select-single-work-package",
        "#project-select-single-work-package-container",
        "#incorrect-token-single-work-package"
      );
    });

    $("#project-select-multiple-work-packages").on("change", async function () {
      const connection = getConnection(false);
      const requestBody = {
        project: $(this).val(),
      };

      try {
        const response = await createWpUtils.createWorkPackagesRequest(connection, requestBody);
        generateCards(response, rowsData.map(() => ""));

        if ($(".mapping-row").length > 0) {
          updateMapping();
        }
        else {
          initializeMapping(response);
        }
      } catch (err) {
        createWpUtils.notify("An error occurred while trying to set the available values!", "error")
      }
     });

    $("#project-select-single-work-package").on("change", async function () {
      const connection = getConnection(true);
      const requestBody = {
        project: $(this).val(),
      };

      try {
        const response = await createWpUtils.createWorkPackagesRequest(connection, requestBody);

        const template = $("#work-package-card-template");
        const container = $("#single-dynamic-fields-container");
        container.empty().addClass("hidden");

        Object.entries(response).forEach(([key, value]) => {
          const id = `wp-${key}`;
          const inputClass = `wp-${key}`;
          const input = createWpUtils.createInput(id, key, inputClass, value);
          container.append(input);
        });

        if (selectedText && String(selectedText).trim() !== "") {
          const subjectInputs = container.find("input[name='subject']");
          if (subjectInputs.length) {
            subjectInputs.first().val(selectedText);
          }
        }

        container.removeClass("hidden");
      } catch (err) {
        createWpUtils.notify("An error occurred while trying to create the inputs!", "error");
      }
    });

    $("#create-single-work-package-form").on("submit", async function (e) {
      e.preventDefault();

      const singleContainer = $("#single-dynamic-fields-container");
      const firstInvalidSingle = findAndOpenFirstInvalid(singleContainer);

      if (firstInvalidSingle) {
        createWpUtils.notify('Please fill the required fields highlighted.', 'error');
        return;
      }

      const $container = $("#single-dynamic-fields-container");
      const project = $("#project-select-single-work-package").val();

      if (!project) {
				createWpUtils.notify('Please select a project.', 'error');
				return;
			}

      const payload = {...createWpUtils.buildPayload($container), 'project': project};
      const connection = $("#connection-select-single-work-package").val();

      if (!connection) {
				createWpUtils.notify('Please select a connection.', 'error');
				return;
			}
      try {
        const response = await createWpUtils.createWorkPackagesRequest(connection, payload);
        resetCreateSingleWorkPackageForm();
        $("#create-work-packages-modal").modal("hide");
        createWpUtils.notify("The Work Package was created successfully!", "done");
      } catch (err) {
        createWpUtils.notify("Failed to create the Work Package!", "error")
      }
    });

    $("#create-multiple-work-packages-form").on("submit", async function (e) {
      e.preventDefault();
      const firstInvalidMultiple = findAndOpenFirstInvalid($(this));
      if (firstInvalidMultiple) {
        createWpUtils.notify('Please fill the required fields highlighted in selected work packages.', 'error');
        return;
      }

      const connection = $("#connection-select-multiple-work-packages").val();

      if (!connection) {
				createWpUtils.notify('Please select a connection.', 'error');
				return;
			}

      const project = $("#project-select-multiple-work-packages").val();

      if (!project) {
        createWpUtils.notify('Please select a project.', 'error');
        return;
      }

      const tasks = [];

      $('.work-package-card').each(function() {
        const card = $(this);
        const isSelected = card.find('.wp-selected').is(':checked');

        if (!isSelected) {
          return;
        }

        const payload = createWpUtils.buildPayload(card);
        payload.project = project;

        const titleEl = card.find('.wp-subject-title');
        titleEl.removeClass('text-success text-danger');

        const p = createWpUtils.createWorkPackagesRequest(connection, payload)
        .then(resp => {
          titleEl.addClass('text-success');
          return { success: true, resp };
        })
        .catch(err => {
          titleEl.addClass('text-danger');
          return { success: false, err };
        });

        tasks.push(p);
      });

      if (tasks.length === 0) {
        createWpUtils.notify('No work packages selected', 'warning');
        return;
      }

      const results = await Promise.all(tasks);
      const allSuccess = results.every(r => r.success === true);
      if (allSuccess) {
        createWpUtils.notify('All work packages created successfully!', 'done');
      } else if (results.some(r => r.success)) {
        createWpUtils.notify('Some work packages were created, some failed.', 'warning');
      } else {
        createWpUtils.notify('Failed to create work packages!', 'error');
      }
    });

    $("#create-multiple-work-packages-cancel-button").on("click", function() {
      resetCreateMultipleWorkPackagesForm();
    });

    $("#create-single-work-package-cancel-button").on("click", function() {
      resetCreateSingleWorkPackageForm();
    });

    $(document).on('mouseup', function () {
      const selection = window.getSelection();
      const text = selection.toString().trim();

      if (!text) {
        $('#selection-menu').hide();
        return;
      }

      const range = selection.getRangeAt(0);
      const rect = range.getBoundingClientRect();

      if (rect.width === 0 && rect.height === 0) {
          $('#selection-menu').hide();
          return;
      }

			const menu = $('#selection-menu');

      menu
        .css({
          display: 'block',
          position: 'fixed',
          zIndex: 1050,
          top: rect.top - menu.outerHeight() - 8 + 'px',
          left: rect.left + rect.width / 2 - menu.outerWidth() / 2 + 'px'
        });

      let node = range.commonAncestorContainer;
      if (node.nodeType === Node.TEXT_NODE) {
        node = node.parentNode;
      }

      const isInTable = $(node).closest("table").length;

      if (isInTable) {
        $('#create-wp-from-table').removeClass('hidden');
      } else {
        $('#create-wp-from-table').addClass('hidden');
      }
    });

    $(document).on('mousedown', function(e) {
      if (!$(e.target).closest('#selection-menu').length) {
        $('#selection-menu').hide();
      }
    });

    $(document).on("click", ".wp-selected, label[for^='wp-selected']", function(e) {
      e.stopPropagation();
    });

    $(document).on('change', '#select-all-work-packages', function () {
      const checked = $(this).is(':checked');
      $('#work-packages-container .wp-selected').prop('checked', checked);
    });

    $(document).on('change', '.wp-selected', function () {
      const total = $('#work-packages-container .wp-selected').length;
      const checked = $('#work-packages-container .wp-selected:checked').length;

      $('#select-all-work-packages').prop('checked', total === checked);
    });
  });
})
